```bicep
// Deny inbound HTTP from Internet on an existing NSG
resource nsg 'Microsoft.Network/networkSecurityGroups@2023-09-01' existing = {
  name: '<example_resource_name>'
}

resource denyHttp 'Microsoft.Network/networkSecurityGroups/securityRules@2023-09-01' = {
  name: '${nsg.name}/Deny-HTTP-Internet'
  properties: {
    priority: 100
    direction: 'Inbound'
    access: 'Deny'                 // CRITICAL: Denies the HTTP rule so it no longer allows Internet traffic
    protocol: 'Tcp'
    sourceAddressPrefix: 'Internet' // CRITICAL: Targets traffic coming from the Internet
    destinationAddressPrefix: '*'
    sourcePortRange: '*'
    destinationPortRange: '80'      // CRITICAL: Blocks port 80 (HTTP)
  }
}
```

