```bicep
// NSG with RDP allowed only from a restricted CIDR (not Internet)
resource nsg 'Microsoft.Network/networkSecurityGroups@2023-09-01' = {
  name: '<example_resource_name>'
  location: '<region>'
  properties: {
    securityRules: [
      {
        name: 'Allow-RDP-Restricted'
        properties: {
          priority: 100
          direction: 'Inbound'
          access: 'Allow'
          protocol: 'Tcp'
          sourcePortRange: '*'
          destinationPortRange: '3389'
          destinationAddressPrefix: '*'
          sourceAddressPrefix: '<AUTHORIZED_CIDR>' // CRITICAL: restrict source; not "Internet", "*", or "0.0.0.0/0" to pass the check
        }
      }
    ]
  }
}
