```bicep
// Enable server-level auditing to an existing Storage Account
param sqlServerName string = "<example_resource_name>"
param storageAccountName string = "<example_resource_name>"

resource sql 'Microsoft.Sql/servers@2021-11-01' existing = {
  name: sqlServerName
}

resource sa 'Microsoft.Storage/storageAccounts@2023-01-01' existing = {
  name: storageAccountName
}

resource audit 'Microsoft.Sql/servers/auditingSettings@2021-11-01-preview' = {
  name: 'default'
  parent: sql
  properties: {
    state: 'Enabled' // Critical: turns on auditing
    storageEndpoint: 'https://${sa.name}.blob.core.windows.net/' // Critical: audit log destination
    storageAccountAccessKey: listKeys(sa.id, '2023-01-01').keys[0].value // Critical: grants write access to logs
  }
}
```

