  name: 'default'
  parent: sa
  properties: {
    protocolSettings: {
      smb: {
        channelEncryption: [ 'AES-256-GCM' ] // CRITICAL: Allows AES-256-GCM for SMB channel encryption to pass the check
      }
    }
  }
}
```

